struct V{double x,y,z;};
static inline V operator+(V a,V b){return {a.x+b.x,a.y+b.y,a.z+b.z};}
static inline V operator-(V a,V b){return {a.x-b.x,a.y-b.y,a.z-b.z};}
static inline V operator*(V a,double s){return {a.x*s,a.y*s,a.z*s};}
static inline V operator/(V a,double s){return {a.x/s,a.y/s,a.z/s};}
static inline double dot(V a,V b){return a.x*b.x+a.y*b.y+a.z*b.z;}
static inline V cross(V a,V b){return {a.y*b.z-a.z*b.y,a.z*b.x-a.x*b.z,a.x*b.y-a.y*b.x};}
static inline double n2(V a){return dot(a,a);} static inline double len(V a){return sqrt(n2(a));}
static inline V norm(V a){double l=len(a);return l>0?a/l:V{0,0,0};}
struct F{int v[3];};
struct SF{int v[3]; unsigned char on=1;};
static int N,M; static vector<V> O; static vector<F> OF; static double Dg=1,EPS=.05,ORIENT=1; static V MN,MX,CEN; static chrono::steady_clock::time_point T0;
